from collections import defaultdict

def build_index(docs):
    index = defaultdict(list)
    for doc_id, text in docs.items():
        words = set(text.lower().split())
        for word in words:
            index[word].append(doc_id)
    return dict(index)

# Mock Database
my_docs = {
    1: "Information Retrieval is fun",
    2: "Search engines and retrieval",
    3: "Fun with information"
}

inverted_index = build_index(my_docs)
print(f"Postings for 'Retrieval': {inverted_index.get('retrieval')}")
print(f"Postings for 'Information': {inverted_index.get('information')}")
